function isAwaitUsingStart(parser: Parser): boolean {
  let { index } = parser;
  const { source, end } = parser;

  while (index < end) {
    const char = source.charCodeAt(index);
    if (char === 0x20 || char === 0x09 || char === 0x0b || char === 0x0c) {
      index++;
    } else if (char === 0x2f && source.charCodeAt(index + 1) === 0x2a) {
      const commentEnd = source.indexOf('*/', index + 2);
      if (commentEnd < 0 || /[\r\n]/.test(source.slice(index + 2, commentEnd))) return false;
      index = commentEnd + 2;
    } else {
      break;
    }
  }

  return source.startsWith('using', index) && !/[\w$]/.test(source[index + 5] ?? '');
}

function isUsingDeclarationStart(parser: Parser): boolean {
  let { index } = parser;
  const { source, end } = parser;

  while (index < end) {
    const char = source.charCodeAt(index);
    if (char === 0x20 || char === 0x09 || char === 0x0b || char === 0x0c) {
      index++;
    } else if (char === 0x2f && source.charCodeAt(index + 1) === 0x2a) {
      const commentEnd = source.indexOf('*/', index + 2);
      if (commentEnd < 0 || /[\r\n]/.test(source.slice(index + 2, commentEnd))) return false;
      index = commentEnd + 2;
    } else {
      break;
    }
  }

  const char = source.charCodeAt(index);
  return (
    char === 0x5b ||
    char === 0x7b ||
    char === 0x5c ||
    char === 0x24 ||
    char === 0x5f ||
    (char >= 0x41 && char <= 0x5a) ||
    (char >= 0x61 && char <= 0x7a)
  );
}

